var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"수수께끼가 모두 풀렸다고?","JPN":"謎が解けた？","ENG":"The mystery has been solved?","TWN":"謎底都解開了？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"범인을 찾았다는 뜻이야?","JPN":"犯人を見つけたってこと？","ENG":"Do you know who the perpetrator is?","TWN":"妳是說找到兇手了？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"맞아요. 그리고 범인은 바로 이 장소에 있습니다.","JPN":"はい、そして犯人はここにいます。","ENG":"Yes, and she's right here and now.","TWN":"是的，那個兇手就在這裡。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"방금 그 얘기로 범인을 알아차렸다고? 어떻게?","JPN":"今の話でわかったって言うわけ？　どうやって？","ENG":"You found the perpetrator after those two questions. How?","TWN":"就通過剛剛那幾個問題找到了兇手？怎麼可能？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"처음으로 이상하다고 생각했던 건 선배의 불완전한 알리바이였어요.","JPN":"最初、おかしいと思ったのは先輩の不完全なアリバイでした。","ENG":"The first strange thing I noticed was Shiyoon's incomplete alibi.","TWN":"剛開始我覺得很奇怪的是前輩有個並不完美的不在場證明。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"애초에 그 선배가 이런 귀찮은 일을 저지를 성격도 아니지만......","JPN":"それに、先輩がこんな面倒なことをする性格でもありませんし……","ENG":"First of all, he's not the type who would bother to go through all this trouble,","TWN":"而且依前輩的性格，他並不是會做這種麻煩事的人……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"만약 정말 성야의 살인마였다면 왜 그렇게 어설프게 움직였을까요?","JPN":"もし、本当に聖夜の殺人鬼だったなら、なぜあんな怪しい行動を取ったのか。","ENG":"and even if he was, he wouldn't have done it so sloppily like this.","TWN":"如果他真的是耶誕的嫌疑犯，那他為什麼會那麼粗心？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"어설퍼? 어떤 부분이?","JPN":"怪しい？　どこがですか？","ENG":"So sloppily? In which part?","TWN":"粗心？妳的意思是？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배는 그 촌스러운 출근복을 스무 벌이나 사다 놓고 매일 갈아입는 사람이에요.","JPN":"先輩はあのダサい服を二十着も用意して、毎日着替える人です。","ENG":"Shiyoon is so fastidious that he bought twenty sets of tacky-looking clothes, of the same design, so he could wear a fresh one every day.","TWN":"前輩是一個買二十套一模一樣的工作服，然後每天換洗的人。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그런 사람이 어째서 지우는 데 몇 분 걸리지도 않을 커피 자국을 남겨 두는 바람에 의심 받게 됐을까요?","JPN":"そんな人が、どうして落とすのに数分もかからない\\nコーヒーの染みを残したまま、私が疑うように仕向けたのでしょうか？","ENG":"If he really was the mastermind, he would never have left the coffee stains on him, which he could have gotten rid of in a few minutes.","TWN":"那樣的人為什麼身上會留著幾分鐘就可以擦掉的咖啡漬，然後讓人懷疑呢？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그것뿐만이 아니에요.","JPN":"それだけではありません。","ENG":"That's not all.","TWN":"不僅如此。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"선배가 작정하고 기습했다면 우리 둘을 쓰러뜨리긴 어렵지 않았을 거예요.","JPN":"先輩が本気で奇襲したのであれば、私たち二人を倒すのはそう難しくなかったはずです。","ENG":"If Shiyoon really wanted to defeat us, he could have done it easily.","TWN":"如果前輩真要襲擊，那麼他可以輕而易舉打敗我們。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 선배는 매번 적당히 상대하다가 도망쳐 버렸죠.","JPN":"でも先輩は、毎回適当に私たちの相手をしては逃げてしまいました。","ENG":"But he always ran away after a while,","TWN":"可前輩每次都是適當的出手之後便逃走了。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"꼭 우리를 쓰러뜨리면 안 되는 것처럼요.","JPN":"私たちを倒してはいけないかのように。","ENG":"as if he had reasons not to take us down.","TWN":"就好像是刻意的。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"우릴 쓰러뜨리면 안 된다고? 그럴 이유가 있어?","JPN":"アタシたちを倒してはいけない？　なんで？","ENG":"Reasons not to take us down?","TWN":"刻意？為什麼？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};